"""Effect handlers for Pokémon attacks (Batch 6 — Phase 2).

Each handler is registered as:
    register_attack(card_id, attack_index, handler_func)

Handlers that require player choices are generator functions that yield
ChoiceRequest objects and receive back the chosen Action.

Flat-damage-only attacks with no effects are deliberately NOT registered here;
they fall through to EffectRegistry._default_damage which handles them correctly.
"""

from __future__ import annotations

import logging
import random as _random
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    from app.engine.state import GameState
    from app.engine.actions import Action

from app.engine.state import (
    EnergyType,
    Phase,
    StatusCondition,
    Zone,
)
from app.engine.effects.base import (
    ChoiceRequest,
    apply_weakness_resistance,
    check_ko,
    draw_cards,
    get_tool_damage_bonus,
    has_tool,
    parse_damage,
)
from app.engine.effects.abilities import (
    has_adrena_power,
    has_adrena_pheromone,
    has_battle_cage,
    has_cheer_on_to_glory,
    has_cornerstone_stance,
    has_extra_helpings,
    has_flower_curtain,
    has_mysterious_rock_inn,
    has_spherical_shield,
    has_stone_palace,
    has_tundra_wall,
    repelling_veil_protects,
)
from app.cards import registry as card_registry

logger = logging.getLogger(__name__)

_TR_ENERGY_ID = "sv10-182"  # Team Rocket's Energy (used by multiple handlers)

# Ancient and Future Pokémon card-def IDs (Paradox Rift / Temporal Forces era)
_ANCIENT_CARD_IDS = frozenset({
    "sv05-050", "svp-127",   # Walking Wake ex
    "sv05-077", "svp-076",   # Scream Tail
    "sv05-078", "svp-097",   # Flutter Mane
    "sv05-075",              # Brute Bonnet
    "sv05-076",              # Brute Bonnet ex (if present)
    "sv05-119", "svp-148",   # Koraidon
    "sv05-120",              # Koraidon ex
    "sv05-047",              # Sandy Shocks
    "sv05-048",              # Sandy Shocks ex
    "sv05-068",              # Roaring Moon
    "sv05-069",              # Roaring Moon ex
    "sv05-055",              # Slither Wing
    "sv05-056",              # Slither Wing
    "sv05-074",              # Brute Bonnet
})

_FUTURE_CARD_IDS = frozenset({
    "sv05-062", "svp-170",        # Iron Thorns
    "sv05-079", "svp-143",        # Iron Valiant
    "sv05-080", "svp-144",        # Iron Valiant
    "sv05-081", "svp-146",        # Iron Crown ex
    "sv05-121", "svp-210",        # Miraidon
    "sv05-122", "svp-083",        # Miraidon ex
    "sv08-069",                   # Miraidon (SSP)
    "sv05-025", "svp-025",        # Iron Leaves ex
    "sv05-118",                   # Iron Treads
    "sv05-139",                   # Iron Jugulis
    "sv05-082",                   # Iron Hands ex
    "sv05-083",                   # Iron Boulder
})

_IRON_CROWN_EX_IDS = frozenset({"sv05-081", "svp-146"})  # excluded from Cobalt Command


def _is_ancient(pokemon) -> bool:
    return pokemon.card_def_id in _ANCIENT_CARD_IDS


def _is_future(pokemon) -> bool:
    return pokemon.card_def_id in _FUTURE_CARD_IDS


# ──────────────────────────────────────────────────────────────────────────────
# Shared damage helpers
# ──────────────────────────────────────────────────────────────────────────────

def _apply_damage(
    state: "GameState",
    action: "Action",
    base_damage: int,
    bypass_wr: bool = False,
    bypass_defender_effects: bool = False,
    bypass_resistance_only: bool = False,
) -> int:
    """Apply base_damage through the standard pipeline and return final_damage.

    Args:
        bypass_wr: Skip weakness/resistance (for Demolish).
        bypass_defender_effects: Skip ability blocks and Payapa Berry
            (for Shred, Superb Scissors, Demolish).
        bypass_resistance_only: Skip only resistance, not weakness (for Rock Tumble etc.).
    """
    player = state.get_player(action.player_id)
    opp = state.get_opponent(action.player_id)
    opp_id = state.opponent_id(action.player_id)

    if not player.active or not opp.active:
        return 0

    attacker = player.active
    defender = opp.active
    cdef = card_registry.get(attacker.card_def_id)
    attack = (cdef.attacks[action.attack_index]
              if cdef and action.attack_index is not None
              and action.attack_index < len(cdef.attacks) else None)

    if base_damage <= 0:
        state.emit_event(
            "attack_no_damage",
            attacker=attacker.card_name,
            attack_name=attack.name if attack else "",
        )
        return 0

    # prevent_damage_one_turn (Marill Hide / Hop's Phantump Splashing Dodge)
    if defender.prevent_damage_one_turn:
        state.emit_event("damage_prevented", card=defender.card_name,
                         reason="prevent_damage_one_turn")
        return 0

    # prevent_damage_threshold (Metapod Harden): prevent damage ≤ threshold next turn
    if defender.prevent_damage_threshold > 0:
        # Compute base damage before W/R to check threshold
        _check_cdef = card_registry.get(action.card_id) if hasattr(action, "card_id") else None
        _check_atk = (_check_cdef.attacks[action.attack_index]
                      if _check_cdef and action.attack_index < len(_check_cdef.attacks) else None)
        _check_base = base_damage if base_damage is not None else (_check_atk.damage if _check_atk else 0)
        if _check_base <= defender.prevent_damage_threshold:
            state.emit_event("damage_prevented", card=defender.card_name,
                             reason="prevent_damage_threshold")
            return 0

    # Resolute Heart (me02.5-057 Pikachu ex): eligible only if at full HP before this attack
    if defender.card_def_id == "me02.5-057":
        defender.resolute_heart_eligible = (
            defender.damage_counters == 0 and defender.current_hp == defender.max_hp
        )
    # Sturdy (sv10.5b-052 Crustle): same Resolute Heart mechanic
    if defender.card_def_id == "sv10.5b-052":
        defender.resolute_heart_eligible = (
            defender.damage_counters == 0 and defender.current_hp == defender.max_hp
        )
    # Resolute Heart (sv08-057 Pikachu ex SSP): same mechanic
    if defender.card_def_id == "sv08-057":
        defender.resolute_heart_eligible = (
            defender.damage_counters == 0 and defender.current_hp == defender.max_hp
        )

    total = base_damage + state.active_player_damage_bonus
    if state.active_player_damage_bonus_vs_ex:
        def_cdef = card_registry.get(defender.card_def_id)
        if def_cdef and def_cdef.is_ex:
            total += state.active_player_damage_bonus_vs_ex
    # Sunny Day (sv09-007 Lilligant): +20 for Grass/Fire attacks
    if state.sunny_day_active:
        _atk_cdef = card_registry.get(attacker.card_def_id)
        if _atk_cdef and any(t in (_atk_cdef.types or []) for t in ("Grass", "Fire")):
            total += 20
    if has_adrena_power(attacker):
        total += 100
    total += attacker.attack_damage_bonus

    # Compound Eyes (sv06.5-002 Galvantula): +50 to attacks vs Active before W/R
    if any(p.card_def_id == "sv06.5-002" for p in _in_play(player)):
        total += 50

    # Cobalt Command (sv05-081 / svp-146 Iron Crown ex): Future Pokémon (excl. Iron Crown ex) do +20
    if attacker.card_def_id not in _IRON_CROWN_EX_IDS and _is_future(attacker):
        _atk_player_cc = state.get_player(action.player_id)
        if any(p.card_def_id in _IRON_CROWN_EX_IDS for p in _in_play(_atk_player_cc)):
            total += 20
            state.emit_event("cobalt_command_bonus", player=action.player_id,
                             attacker=attacker.card_name)

    # Azure Seas (sv05-050 / svp-127 Walking Wake ex): bypass ALL effects on opp Active
    if attacker.card_def_id in ("sv05-050", "svp-127"):
        bypass_defender_effects = True

    if not bypass_wr:
        total = apply_weakness_resistance(total, attacker, defender, state, opp_id,
                                          skip_resistance=bypass_resistance_only)

    if bypass_defender_effects:
        total += _attacker_tool_bonus(attacker, defender, state)
    else:
        total += get_tool_damage_bonus(
            attacker, defender, action.attack_index or 0, state, action.player_id
        )
    total = max(0, total)

    if not bypass_defender_effects:
        if defender.protected_from_ex and cdef and cdef.is_ex:
            total = 0
        elif has_cornerstone_stance(defender, attacker):
            total = 0
        elif has_mysterious_rock_inn(defender, attacker):
            total = 0
        elif has_adrena_pheromone(defender):
            if _random.choice([True, False]):
                state.emit_event(
                    "adrena_pheromone_blocked",
                    player=opp_id,
                    card=defender.card_name,
                )
                total = 0
        # Armor Tail (sv05-108 Farigiraf ex): prevent all damage from Basic Pokémon ex
        elif defender.card_def_id == "sv05-108" and cdef and cdef.is_ex:
            attacker_def_at = card_registry.get(attacker.card_def_id)
            if attacker_def_at and (attacker_def_at.stage or "").lower() == "basic":
                state.emit_event("damage_prevented", card=defender.card_name,
                                 reason="armor_tail")
                return 0
        # C.O.D.E.: Protect (sv08-069 Miraidon): Future Pokémon immune to ex damage next turn
        if (opp.future_effect_immunity and _is_future(defender)
                and cdef and cdef.is_ex):
            state.emit_event("damage_prevented", card=defender.card_name,
                             reason="code_protect")
            return 0

        # Anachronism Repulsor (sv06.5-009 Iron Moth): block damage from Ancient Pokémon
        if defender.prevent_damage_from_ancient and _is_ancient(attacker):
            state.emit_event("damage_prevented", card=defender.card_name,
                             reason="prevent_damage_from_ancient")
            return 0

    if not bypass_defender_effects:
        # Thick Fat (me02-022 Dewgong): reduce damage by 30 from Fire/Water attackers
        if defender.card_def_id == "me02-022":
            attacker_def = card_registry.get(attacker.card_def_id)
            if attacker_def and any(t in (attacker_def.types or []) for t in ("Fire", "Water")):
                total = max(0, total - 30)

        # Diamond Coat (me02-041 Mega Diancie ex): reduce damage by 30
        if defender.card_def_id == "me02-041":
            total = max(0, total - 30)

        # Crown Opal: prevent all damage from Basic non-Colorless attackers
        if defender.prevent_damage_from_basic_noncolorless:
            attacker_def = card_registry.get(attacker.card_def_id)
            if attacker_def:
                is_basic = attacker_def.stage.lower() == "basic"
                is_only_colorless = (attacker_def.types or []) == ["Colorless"]
                if is_basic and not is_only_colorless:
                    state.emit_event("damage_prevented", card=defender.card_name,
                                     reason="crown_opal")
                    return 0

        # prevent_damage_from_basic (Archaludon Coated Attack, Mega Manectric ex Flash Ray)
        if defender.prevent_damage_from_basic:
            attacker_def = card_registry.get(attacker.card_def_id)
            if attacker_def and (attacker_def.stage or "").lower() == "basic":
                state.emit_event("damage_prevented", card=defender.card_name,
                                 reason="prevent_damage_from_basic")
                return 0

        # Intimidating Fang (me01-024 Pyroar): opp attacks do 30 less
        if defender.card_def_id == "me01-024":
            total = max(0, total - 30)

        # Gear Coating (sv10.5b-063 Klinklang): Metal Pokémon with Metal energy take 20 less damage
        _opp_in_play_gc = ([opp.active] if opp.active else []) + list(opp.bench)
        if any(p.card_def_id == "sv10.5b-063" for p in _opp_in_play_gc):
            _def_cdef_gc = card_registry.get(defender.card_def_id)
            if (_def_cdef_gc and "Metal" in (_def_cdef_gc.types or [])
                    and any(att.energy_type == EnergyType.METAL
                            for att in defender.energy_attached)):
                total = max(0, total - 20)

        # Bouffer (sv10.5w-077 Bouffalant ex): takes 30 less damage from attacks
        if defender.card_def_id == "sv10.5w-077":
            total = max(0, total - 30)

        # Mud Coat (sv10-108 Mudsdale): takes 30 less damage from attacks
        if defender.card_def_id == "sv10-108":
            total = max(0, total - 30)

        # Rock Armor (sv09-082 Regirock): 30 less damage if any energy attached
        if defender.card_def_id == "sv09-082" and defender.energy_attached:
            total = max(0, total - 30)

        # Stone Palace (sv10-086 Steven's Carbink): Steven's Pokémon take 30 less damage
        if "Steven's" in defender.card_name:
            opp_id_for_stone = state.opponent_id(action.player_id)
            if has_stone_palace(state, opp_id_for_stone):
                total = max(0, total - 30)

        # Safeguard (sv08.5-040 Sylveon): prevent all damage from Pokémon ex
        if defender.card_def_id == "sv08.5-040" and cdef and cdef.is_ex:
            state.emit_event("damage_prevented", card=defender.card_name, reason="safeguard")
            return 0

        # Fur Coat (sv08.5-088 Furfrou): takes 20 less damage from attacks
        if defender.card_def_id == "sv08.5-088":
            total = max(0, total - 20)

        # Solid Body (sv08-054 Cetitan): takes 30 less damage from attacks
        if defender.card_def_id == "sv08-054":
            total = max(0, total - 30)

        # Sparkling Scales (sv08-042 Milotic ex): no damage from Tera Pokémon
        if defender.card_def_id == "sv08-042" and cdef and getattr(cdef, "is_tera", False):
            state.emit_event("damage_prevented", card=defender.card_name,
                             reason="sparkling_scales")
            return 0

        # Protective Bell (sv08.5-067 Bronzong): all defender's Pokémon take 10 less damage
        opp_for_bell = state.get_opponent(action.player_id)
        if any(p.card_def_id == "sv08.5-067" for p in _in_play(opp_for_bell)):
            total = max(0, total - 10)

        # Full Metal Lab (sv05-148): Metal Pokémon take 30 less damage from attacks (after W/R)
        if (state.active_stadium
                and state.active_stadium.card_def_id == "sv05-148"):
            _def_cdef_fml = card_registry.get(defender.card_def_id)
            if _def_cdef_fml and "Metal" in (_def_cdef_fml.types or []):
                total = max(0, total - 30)
                state.emit_event("full_metal_lab_reduction", player=opp_id,
                                 card=defender.card_name)

    # Supreme Overlord (me02.5-148 Kingambit): +30 per prize opponent has taken
    if attacker.card_def_id == "me02.5-148":
        prizes_taken = 6 - state.get_player(action.player_id).prizes_remaining
        total += prizes_taken * 30

    # Cheer On to Glory (sv10-008 Cynthia's Roserade): Cynthia's Pokémon do 30 more damage
    if "Cynthia's" in attacker.card_name and has_cheer_on_to_glory(state, action.player_id):
        total += 30

    # Extra Helpings (sv09-117 Hop's Snorlax): Hop's Pokémon do 30 more damage
    if "Hop's" in attacker.card_name and has_extra_helpings(state, action.player_id):
        total += 30
        state.emit_event("extra_helpings_bonus", player=action.player_id,
                         attacker=attacker.card_name)

    # Lose Cool (sv10-092 Annihilape): if 2+ damage counters on attacker, +120 damage
    if attacker.card_def_id == "sv10-092" and attacker.damage_counters >= 2:
        total += 120

    # Excited Power (me02-062 Seviper): +120 for Darkness Pokémon if Seviper in play
    _attacker_cdef2 = card_registry.get(attacker.card_def_id)
    if _attacker_cdef2 and "Darkness" in (_attacker_cdef2.types or []):
        _atk_player = state.get_player(action.player_id)
        _sev_in_play = ([_atk_player.active] if _atk_player.active else []) + list(_atk_player.bench)
        if any(p.card_def_id == "me02-062" for p in _sev_in_play):
            total += 120
            state.emit_event("excited_power_bonus", player=action.player_id,
                             attacker=attacker.card_name)

    # Powerful a-Salt (me01-084 Garganacl): +30 for all Fighting attackers on attacker's side
    _atk_player2 = state.get_player(action.player_id)
    _atk_in_play2 = ([_atk_player2.active] if _atk_player2.active else []) + list(_atk_player2.bench)
    if any(p.card_def_id == "me01-084" for p in _atk_in_play2):
        _atk_cdef3 = card_registry.get(attacker.card_def_id)
        if _atk_cdef3 and "Fighting" in (_atk_cdef3.types or []):
            total += 30
            state.emit_event("powerful_a_salt_bonus", player=action.player_id,
                             attacker=attacker.card_name)

    # Regal Cheer (sv10.5b-003 Serperior ex): +20 for all attackers on attacker's side
    _atk_player3 = state.get_player(action.player_id)
    _atk_in_play3 = ([_atk_player3.active] if _atk_player3.active else []) + list(_atk_player3.bench)
    if any(p.card_def_id == "sv10.5b-003" for p in _atk_in_play3):
        total += 20
        state.emit_event("regal_cheer_bonus", player=action.player_id,
                         attacker=attacker.card_name)

    # Victory Cheer (sv08-021 Victini): Fire-type Evolution Pokémon do 10 more damage
    _atk_player4 = state.get_player(action.player_id)
    _atk_in_play4 = ([_atk_player4.active] if _atk_player4.active else []) + list(_atk_player4.bench)
    if any(p.card_def_id == "sv08-021" for p in _atk_in_play4):
        _vic_cdef = card_registry.get(attacker.card_def_id)
        if (_vic_cdef and "Fire" in (_vic_cdef.types or [])
                and (_vic_cdef.stage or "").lower() not in ("basic", "")):
            total += 10
            state.emit_event("victory_cheer_bonus", player=action.player_id,
                             attacker=attacker.card_name)

    # Mighty Shell (sv10.5b-023 Carracosta): if defender is Carracosta AND attacker has Special Energy → 0 damage
    _SPECIAL_ENERGY_IDS = {"me02.5-216", "me03-086", "me03-088", "sv05-161",
                            "sv06-167", "sv08-191", "sv10-182", "sv10.5w-086"}
    if defender.card_def_id == "sv10.5b-023":
        if any(ea.card_def_id in _SPECIAL_ENERGY_IDS for ea in attacker.energy_attached):
            state.emit_event("mighty_shell_blocked", defender=defender.card_name,
                             attacker=attacker.card_name)
            return 0

    total = max(0, total)
    if not bypass_defender_effects and has_tundra_wall(state, opp_id):
        if any(att.energy_type == EnergyType.WATER for att in defender.energy_attached):
            total = max(0, total - 50)
    if not bypass_defender_effects and defender.incoming_damage_reduction > 0:
        total = max(0, total - defender.incoming_damage_reduction)
    if attacker.attack_damage_reduction > 0:
        total = max(0, total - attacker.attack_damage_reduction)
    defender.current_hp -= total
    defender.damage_counters += total // 10
    state.emit_event(
        "attack_damage",
        attacker=attacker.card_name,
        defender=defender.card_name,
        attack_name=attack.name if attack else "",
        base_damage=base_damage,
        final_damage=total,
    )

    # Spiky Energy (sv09-159): if defender is Active and has Spiky Energy attached, put 2 counters on attacker
    if total > 0 and attacker.current_hp > 0:
        _def_player_se = state.get_player(opp_id)
        _has_spiky = (
            defender is _def_player_se.active
            and any(
                att.source_card_id and any(
                    c.instance_id == att.source_card_id and c.card_def_id == "sv09-159"
                    for c in _def_player_se.discard + _def_player_se.hand + list(_def_player_se.deck)
                )
                for att in defender.energy_attached
            )
        )
        if _has_spiky:
            attacker.current_hp -= 20
            attacker.damage_counters += 2
            state.emit_event("spiky_energy_triggered", player=opp_id,
                             attacker=attacker.card_name)
            check_ko(state, attacker, action.player_id)
            if state.phase == Phase.GAME_OVER:
                return total

    # Counterattack Quills (me02.5-068 Hop's Pincurchin ex): place 3 counters on attacker
    if (defender.card_def_id == "me02.5-068"
            and total > 0
            and attacker.current_hp > 0):
        attacker.current_hp -= 30
        attacker.damage_counters += 3
        state.emit_event("counterattack_quills_triggered",
                         defender=defender.card_name,
                         attacker=attacker.card_name)
        check_ko(state, attacker, action.player_id)
        if state.phase == Phase.GAME_OVER:
            return total

    # Automated Combat (sv05-139 Iron Jugulis): when damaged, put 3 counters on attacker
    if (defender.card_def_id == "sv05-139"
            and total > 0
            and attacker.current_hp > 0):
        attacker.current_hp -= 30
        attacker.damage_counters += 3
        state.emit_event("automated_combat_triggered", player=opp_id,
                         attacker=attacker.card_name)
        check_ko(state, attacker, action.player_id)
        if state.phase == Phase.GAME_OVER:
            return total

    # Spiteful Swirl (me01-087 Spiritomb): when Spiritomb on defender's side AND defender is Dark type, place 10 HP on attacker
    if total > 0 and attacker.current_hp > 0:
        _def_player = state.get_player(opp_id)
        _def_in_play = ([_def_player.active] if _def_player.active else []) + list(_def_player.bench)
        if any(p.card_def_id == "me01-087" for p in _def_in_play):
            _def_cdef = card_registry.get(defender.card_def_id)
            if _def_cdef and "Darkness" in (_def_cdef.types or []):
                attacker.current_hp -= 10
                attacker.damage_counters += 1
                state.emit_event("spiteful_swirl_triggered", player=opp_id,
                                 attacker=attacker.card_name)
                check_ko(state, attacker, action.player_id)
                if state.phase == Phase.GAME_OVER:
                    return total

    # Poison Point (sv10.5b-056 Scolipede): when Scolipede takes damage, poison the attacker
    if total > 0 and defender.card_def_id == "sv10.5b-056" and attacker.current_hp > 0:
        attacker.status_conditions.add(StatusCondition.POISONED)
        state.emit_event("poison_point_triggered", player=opp_id,
                         attacker=attacker.card_name)

    # Counterattacking Crest (me02.5-135 Mega Scrafty ex): place 5 counters on attacker
    if (defender.card_def_id == "me02.5-135"
            and total > 0
            and attacker.current_hp > 0):
        attacker.current_hp -= 50
        attacker.damage_counters += 5
        state.emit_event("counterattacking_crest_triggered",
                         defender=defender.card_name,
                         attacker=attacker.card_name)
        check_ko(state, attacker, action.player_id)
        if state.phase == Phase.GAME_OVER:
            return total

    # Smog Signals (sv10-125 TR Koffing): when Koffing is active and damaged, bench up to 2 Koffing from deck
    if (total > 0
            and defender.card_def_id == "sv10-125"
            and _def_player.active is not None
            and _def_player.active.instance_id == defender.instance_id):
        koffing_in_deck = [c for c in _def_player.deck
                           if c.card_type.lower() in ("pokemon", "pokémon")
                           and "koffing" in c.card_name.lower()]
        for _kof in koffing_in_deck[:2]:
            if len(_def_player.bench) < 5:
                _def_player.deck.remove(_kof)
                _kof.zone = _kof.zone.__class__.BENCH
                _def_player.bench.append(_kof)
        import random as _rnd_smog
        _rnd_smog.shuffle(_def_player.deck)
        state.emit_event("smog_signals_triggered", player=opp_id,
                         card=defender.card_name)

    # Shell Spikes (me03-017 Turtonator): place 3 counters on attacker
    if total > 0 and defender.card_def_id == "me03-017" and attacker.current_hp > 0:
        attacker.current_hp -= 30
        attacker.damage_counters += 3
        state.emit_event("shell_spikes_triggered",
                         defender=defender.card_name, attacker=attacker.card_name)
        check_ko(state, attacker, action.player_id)
        if state.phase == Phase.GAME_OVER:
            return total

    # Incandescent Body (me02.5-027 Numel): Burn attacker when Numel takes damage
    if total > 0 and defender.card_def_id == "me02.5-027" and attacker.current_hp > 0:
        attacker.status_conditions.add(StatusCondition.BURNED)
        state.emit_event("incandescent_body_triggered",
                         defender=defender.card_name, attacker=attacker.card_name)

    # Counterattack (sv08-049 Bruxish): place 3 counters on attacker
    if total > 0 and defender.card_def_id == "sv08-049" and attacker.current_hp > 0:
        attacker.current_hp -= 30
        attacker.damage_counters += 3
        state.emit_event("counterattack_triggered",
                         defender=defender.card_name, attacker=attacker.card_name)
        check_ko(state, attacker, action.player_id)
        if state.phase == Phase.GAME_OVER:
            return total

    # Pummeling Payback (sv07-110 Orthworm ex): place 3 counters on attacker
    if total > 0 and defender.card_def_id == "sv07-110" and attacker.current_hp > 0:
        attacker.current_hp -= 30
        attacker.damage_counters += 3
        state.emit_event("pummeling_payback_triggered",
                         defender=defender.card_name, attacker=attacker.card_name)
        check_ko(state, attacker, action.player_id)
        if state.phase == Phase.GAME_OVER:
            return total

    # Zamazenta Strong Bash: reflect damage back to attacker as counters
    if total > 0 and defender.retaliation_on_damage and attacker.current_hp > 0:
        attacker.current_hp = max(0, attacker.current_hp - total)
        attacker.damage_counters += total // 10
        state.emit_event("zamazenta_retaliation",
                         defender=defender.card_name, attacker=attacker.card_name, damage=total)
        check_ko(state, attacker, action.player_id)
        if state.phase == Phase.GAME_OVER:
            return total

    # Repulsor Axe (sv05-099 Iron Boulder ex): if flag set and attacker hits, put 8 counters on attacker
    if total > 0 and defender.repulsor_axe_active and attacker.current_hp > 0:
        attacker.current_hp -= 80
        attacker.damage_counters += 8
        state.emit_event("repulsor_axe_triggered",
                         defender=defender.card_name, attacker=attacker.card_name)
        check_ko(state, attacker, action.player_id)
        if state.phase == Phase.GAME_OVER:
            return total

    # Lucky Helmet (sv06-158): when Pokémon this tool is on is in Active and damaged, draw 2 for that player
    if total > 0 and "sv06-158" in defender.tools_attached:
        from app.engine.effects.base import draw_cards as _draw_cards_lh
        _draw_cards_lh(state, opp_id, 2)
        state.emit_event("lucky_helmet_triggered", player=opp_id,
                         card=defender.card_name)

    check_ko(state, defender, opp_id)
    return total


def _attacker_tool_bonus(attacker, defender, state) -> int:
    """Return only the attacker's tool bonuses (used when bypassing defender effects)."""
    if state.active_stadium and state.active_stadium.card_def_id == "sv06-153":
        return 0  # Jamming Tower disables all tools

    bonus = 0
    defender_cdef = card_registry.get(defender.card_def_id)
    attacker_cdef = card_registry.get(attacker.card_def_id)

    if has_tool(attacker, "sv05-154") and defender_cdef and defender_cdef.is_ex:
        bonus += 50
    if (has_tool(attacker, "sv10.5w-080")
            and attacker_cdef and not attacker_cdef.has_rule_box
            and defender_cdef and defender_cdef.is_ex):
        bonus += 30
    if (has_tool(attacker, "sv08.5-095")
            and StatusCondition.POISONED in attacker.status_conditions):
        bonus += 40
    return bonus


def _do_default_damage(state: "GameState", action: "Action") -> "GameState":
    """Run the standard damage pipeline via the registry (for side-effect attacks)."""
    from app.engine.effects.registry import EffectRegistry
    return EffectRegistry.instance()._default_damage(state, action)


def _apply_bench_damage(
    state: "GameState",
    target_player_id: str,
    target,
    damage: int,
) -> None:
    """Apply flat bench damage (no W/R), respecting Battle Cage, Flower Curtain, Spherical Shield."""
    if damage <= 0:
        return
    if has_battle_cage(state):
        state.emit_event("bench_damage_blocked", reason="battle_cage",
                         card=target.card_name)
        return
    if has_spherical_shield(state, target_player_id):
        state.emit_event("bench_damage_blocked", reason="spherical_shield",
                         card=target.card_name)
        return
    cdef = card_registry.get(target.card_def_id)
    if has_flower_curtain(state, target_player_id):
        if cdef and not cdef.has_rule_box:
            state.emit_event("bench_damage_blocked", reason="flower_curtain",
                             card=target.card_name)
            return
    if has_tundra_wall(state, target_player_id):
        if any(att.energy_type == EnergyType.WATER for att in target.energy_attached):
            damage = max(0, damage - 50)
            if damage <= 0:
                state.emit_event("bench_damage_blocked", reason="tundra_wall",
                                 card=target.card_name)
                return
    # Curly Wall (sv07-119 / svp-136 Bouffalant): reduce bench damage by 20
    _target_player_cw = state.get_player(target_player_id)
    _BOUFFALANT_IDS = frozenset({"sv07-119", "svp-136"})
    if any(p.card_def_id in _BOUFFALANT_IDS for p in _target_player_cw.bench):
        damage = max(0, damage - 20)
        if damage <= 0:
            state.emit_event("curly_wall_blocked", player=target_player_id,
                             card=target.card_name)
            return
    # So Submerged (sv10-048 Misty's Magikarp): prevent all damage to this benched Magikarp
    if target.card_def_id == "sv10-048":
        state.emit_event("bench_damage_blocked", reason="so_submerged",
                         card=target.card_name)
        return
    target.current_hp -= damage
    target.damage_counters += damage // 10
    state.emit_event(
        "bench_damage",
        player=target_player_id,
        card=target.card_name,
        damage=damage,
    )
    check_ko(state, target, target_player_id)


def _place_bench_counters(
    state: "GameState",
    target_player_id: str,
    target,
    counters: int,
) -> None:
    """Place damage counters on a benched Pokémon (same as bench_damage)."""
    _apply_bench_damage(state, target_player_id, target, counters * 10)


def _is_basic_energy(attachment) -> bool:
    """True if this EnergyAttachment is from a basic energy card."""
    from app.engine.effects.trainers import _is_basic_energy_cdef as _bec
    return _bec(card_registry.get(attachment.card_def_id))


def _in_play(player):
    """All Pokémon in play (active + bench)."""
    pokes = []
    if player.active:
        pokes.append(player.active)
    pokes.extend(player.bench)
    return pokes


def _is_tr_pokemon(pokemon) -> bool:
    """True if this Pokémon's name contains 'Team Rocket's'."""
    return "Team Rocket's" in pokemon.card_name


