    for bench_poke in player.bench:
        bdef = card_registry.get(bench_poke.card_def_id)
        if bdef and (bdef.stage or "").lower() in ("stage2", "stage 2") and "Darkness" in (bdef.types or []):
            bonus = 70
            break
    _apply_damage(state, action, 20 + bonus)


