    if not opp.bench:
        _apply_damage(state, action, 30)
        return
    req = ChoiceRequest(
        "choose_cards",
        player_id=action.player_id,
        options=[b.instance_id for b in opp.bench],
        min_choices=1,
        max_choices=1,
        context={"reason": "primeape_drag_off"},
    )
    resp = yield req
