def _colorful_confection_flag(state, action):
    """sv07-065 Alcremie atk0 — Colorful Confection: search deck for up to 5 Pokémon matching attached energy types."""
    player = state.get_player(action.player_id)
    if not player.active:
        return
    # Collect types from attached energy
    energy_types = set()
    for att in player.active.energy_attached:
        for t in att.provides:
            energy_types.add(t.value.capitalize())
    if not energy_types:
        state.emit_event("attack_no_damage", attacker="Alcremie", attack_name="Colorful Confection",
                         reason="no_energy_attached")
        return
    # Find matching Pokémon in deck
    matching = [c for c in player.deck
                if c.card_type.lower() in ("pokemon", "pokémon")]
    type_matched = []
    for c in matching:
        cdef = card_registry.get(c.card_def_id)
        if cdef and any(t in energy_types for t in (cdef.types or [])):
            type_matched.append(c)
    if not type_matched:
        import random as _r_cc
        _r_cc.shuffle(player.deck)
        state.emit_event("attack_no_damage", attacker="Alcremie", attack_name="Colorful Confection",
                         reason="no_matching_pokemon_in_deck")
        return
    req = ChoiceRequest(
        "choose_cards", action.player_id,
        f"Colorful Confection: choose up to 5 Pokémon matching your attached energy types ({', '.join(energy_types)})",
        cards=type_matched, min_count=0, max_count=5,
    )
    resp = yield req
    chosen_ids = resp.selected_cards if resp and resp.selected_cards else []
    for iid in chosen_ids[:5]:
        card = next((c for c in player.deck if c.instance_id == iid), None)
        if card:
            player.deck.remove(card)
            card.zone = Zone.HAND
            player.hand.append(card)
    import random as _r_cc2
    _r_cc2.shuffle(player.deck)
    state.emit_event("colorful_confection", player=action.player_id, found=len(chosen_ids))
    state.emit_event("attack_no_damage", attacker="Alcremie", attack_name="Colorful Confection")


def _swelling_wish_flag(state, action):
    """sv07-098 Jirachi atk0 — Swelling Wish: attach 1 Basic Energy from discard to a Benched Pokémon."""
    from app.engine.effects.trainers import _is_basic_energy_card, _make_energy_attachment
    player = state.get_player(action.player_id)
    if not player.bench:
        return
    basic_energy = [c for c in player.discard if _is_basic_energy_card(c)]
    if not basic_energy:
        return
    req_energy = ChoiceRequest(
        "choose_cards", action.player_id,
        "Swelling Wish: choose a Basic Energy from your discard pile",
        cards=basic_energy, min_count=1, max_count=1,
    )
    resp_energy = yield req_energy
    chosen_ids = (resp_energy.chosen_card_ids
                  if resp_energy and hasattr(resp_energy, "chosen_card_ids") and resp_energy.chosen_card_ids
                  else [])
    ec = next((c for c in player.discard if c.instance_id == chosen_ids[0]), None) if chosen_ids else None
    if ec is None:
        ec = basic_energy[0]
    req_target = ChoiceRequest(
        "choose_target", action.player_id,
        "Swelling Wish: choose a Benched Pokémon to attach the energy to",
        targets=list(player.bench),
    )
    resp_target = yield req_target
    target = None
    if resp_target and resp_target.target_instance_id:
        target = next((p for p in player.bench
                       if p.instance_id == resp_target.target_instance_id), None)
    if target is None:
        target = player.bench[0]
    player.discard.remove(ec)
    ec.zone = target.zone
    target.energy_attached.append(_make_energy_attachment(ec))
    state.emit_event("swelling_wish_attach", player=action.player_id,
                     target=target.card_name, energy=ec.card_name)


